    bucket_name = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']

    try:
        # Reading s3 file content
        s3_object = s3_resource.Object(bucket_name, key)
        content = s3_object.get()['Body'].read().decode('utf-8')

        # Processing s3 file content
        result = process_image(content) # Replace with your image processing function

        # Writing the processed content back to s3 bucket. Using a different key to avoid overwrite.
        s3_resource.Object(bucket_name, key + '_processed').put(Body=json.dumps(result))

        # Sending SNS notification
        sns_client.publish(
            TopicArn='arn:aws:sns:region:account-id:myTopic',  # replace with your Topic ARN
            Message='Image processed successfully',
        )

        # Writing Logs to CloudWatch
        log_client.create_log_group(
            logGroupName='myLogGroup',  # replace with your log group name
        )
        log_client.create_log_stream(
            logGroupName='myLogGroup',  # replace with your log group name
            logStreamName='myLogStream',  # replace with your log stream name
        )

        log_client.put_log_events(
            logGroupName='myLogGroup',  # replace with your log group name
            logStreamName='myLogStream',  # replace with your log stream name
            logEvents=[
                {
                    'timestamp': int(time.time() * 1000),
                    'message': 'Image processed successfully', 
                },
            ],
        )

    except Exception as e:
        # Send notification for any error during the process.
        sns_client.publish(
            TopicArn='arn:aws:sns:region:account-id:myTopic',  # replace with your Topic ARN
            Message=str(e),
        )

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed Successfully!')
    }

